const raw = $json || {};

const messageId = typeof raw.messageId === 'string' ? raw.messageId.trim() : '';
const threadId = typeof raw.threadId === 'string' ? raw.threadId.trim() : '';
const from = typeof raw.from === 'string' ? raw.from.trim() : '';
const subject = typeof raw.subject === 'string' ? raw.subject.trim() : '';
const snippet = typeof raw.snippet === 'string' ? raw.snippet.trim() : '';
const text = typeof raw.text === 'string' ? raw.text : '';
const executeSubworkflow = raw.executeSubworkflow === true;
const routeWorkflowIds = typeof raw.routeWorkflowIds === 'object' && raw.routeWorkflowIds !== null ? raw.routeWorkflowIds : {};

const error = messageId ? '' : 'Input field messageId is required and must be a non-empty string.';

return [{
  json: {
    messageId,
    threadId,
    from,
    subject,
    snippet,
    text,
    executeSubworkflow,
    routeWorkflowIds,
    okToRoute: !error,
    error
  }
}];

