const raw = $json?.message?.content || $json?.text || $json?.output || '';

const fallback = {
  category: 'unknown',
  confidence: 0,
  reason: 'AI output missing or invalid JSON'
};

let parsed = fallback;
if (typeof raw === 'string' && raw.trim()) {
  try {
    parsed = JSON.parse(raw);
  } catch (error) {
    parsed = fallback;
  }
}

const allowed = new Set(['invoice', 'support', 'newsletter', 'personal', 'spam', 'unknown']);
const category = typeof parsed.category === 'string' ? parsed.category.toLowerCase().trim() : 'unknown';
const normalizedCategory = allowed.has(category) ? category : 'unknown';

let confidence = Number(parsed.confidence);
if (!Number.isFinite(confidence)) confidence = 0;
if (confidence < 0) confidence = 0;
if (confidence > 1) confidence = 1;

const reason = typeof parsed.reason === 'string' ? parsed.reason : '';
const useFallback = confidence < 0.7;
const finalCategory = useFallback ? 'unknown' : normalizedCategory;

const input = $('Normalize and validate input').item.json || {};
const routeWorkflowIds = input.routeWorkflowIds || {};

const workflowIdMap = {
  invoice: routeWorkflowIds.invoice || '',
  support: routeWorkflowIds.support || '',
  newsletter: routeWorkflowIds.newsletter || '',
  personal: routeWorkflowIds.personal || '',
  spam: routeWorkflowIds.spam || '',
  unknown: routeWorkflowIds.unknown || ''
};

return [{
  json: {
    ...input,
    classification: {
      category: finalCategory,
      confidence,
      reason
    },
    route: {
      category: finalCategory,
      workflowId: workflowIdMap[finalCategory] || '',
      workflowName: finalCategory
    },
    shouldExecuteSubworkflow: input.executeSubworkflow === true && !!workflowIdMap[finalCategory]
  }
}];

const data = $('Parse and resolve route').item.json || {};

return [{
  json: {
    ok: true,
    action: 'route',
    messageId: data.messageId || null,
    threadId: data.threadId || null,
    classification: data.classification || null,
    route: data.route || null,
    executed: false,
    response: {
      note: 'No target sub workflow configured for this category. Set routeWorkflowIds and executeSubworkflow=true in caller.'
    }
  }
}];

const data = $('Parse and resolve route').item.json || {};

return [{
  json: {
    ok: true,
    action: 'route',
    messageId: data.messageId || null,
    threadId: data.threadId || null,
    classification: data.classification || null,
    route: data.route || null,
    executed: true,
    response: $json || {}
  }
}];

return [{
  json: {
    ok: false,
    action: 'route',
    messageId: $json.messageId || null,
    threadId: $json.threadId || null,
    classification: null,
    route: null,
    executed: false,
    response: {
      error: $json.error || 'Invalid input'
    }
  }
}];
